import{_ as e,c as l,a0 as i,o as r}from"./chunks/framework.D9MR4Zbk.js";const s=JSON.parse('{"title":"Linux 对比","description":"","frontmatter":{},"headers":[],"relativePath":"blog/linux/linux_compare.md","filePath":"blog/linux/linux_compare.md"}'),t={name:"blog/linux/linux_compare.md"};function n(o,a,h,u,c,p){return r(),l("div",null,a[0]||(a[0]=[i('<h1 id="linux-对比" tabindex="-1">Linux 对比 <a class="header-anchor" href="#linux-对比" aria-label="Permalink to &quot;Linux 对比&quot;">​</a></h1><h2 id="why" tabindex="-1">why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;why&quot;">​</a></h2><p>Linux 发行版众多，有 Arch 系、Debian 系、RHEL 系、SUSE 系等。</p><p>选发行版的本质，一是选择包管理器（软件包生态、活跃度），二是选择其理念（大而全，按需渐进式，配置式），三是选择其适配性（最重要！硬件正常驱动、软件正常运行）。</p><p>在适用各发行版后，因没有及时记录使用体验，每次对比时，都回忆不全。想深入了解只能重新安装体验，费时费力。本文的目的也就是记录下来，便于以后对比。</p><h2 id="how" tabindex="-1">how <a class="header-anchor" href="#how" aria-label="Permalink to &quot;how&quot;">​</a></h2><p>每个发行版会列举优缺点，根据发行版的本质进行列举。</p><p>其次会列举发行版的版本和对比的日期。发行版的优缺点会随更新迭代而变化，过于久远的体验无法展现其当前真正的优缺点。</p><p>最后会列举安装发行版的机器配置。不同机器上，驱动支持不全等问题可能导致发行版使用异常。</p><h2 id="what" tabindex="-1">what <a class="header-anchor" href="#what" aria-label="Permalink to &quot;what&quot;">​</a></h2><h3 id="○-arch" tabindex="-1">○ Arch <a class="header-anchor" href="#○-arch" aria-label="Permalink to &quot;○ Arch&quot;">​</a></h3><p>衍生版：</p><ul><li>EndeavourOS：配合 gnome 桌面使用，占用低</li></ul><h3 id="○-debian" tabindex="-1">○ Debian <a class="header-anchor" href="#○-debian" aria-label="Permalink to &quot;○ Debian&quot;">​</a></h3><p>优点：</p><ul><li>稳定</li><li>资料丰富</li><li>软件包丰富，稳定版源的更新频率也比以前快一些</li></ul><p>elementory OS：</p><ul><li>基于 Debian</li><li>界面精美，类似 macOS，并制作了一系列同风格的默认软件</li><li>Pantheon DE 基于 GNOME</li><li>注重隐私和安全，默认不包含遥测，提供不错的权限管理</li></ul><p>KDE neon：</p><ul><li>如果需要 Ubuntu 生态，推荐！</li><li>基于最新的 Ubuntu LTS</li><li>KDE 团队出品，搭载最适配、最新的 KDE</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://www.cnblogs.com/smoggy/p/17177263.html" target="_blank" rel="noreferrer">最小化安装debian</a>，testing 软件源，sway wm，wofi，waybar，alacritty</li></ul>',22)]))}const b=e(t,[["render",n]]);export{s as __pageData,b as default};
